#!/usr/bin/env python
"""
Bootstrap: Core Demand Generator + Ring Enumerator (full MABE)
  - core/ring_enumerator.py: 40 ring systems, positional decoration,
    31 unified decorators (glycan + metal), Backbone/Arm conversion
  - core/demand_generator.py: unified demand-driven generation for
    metal (HSAB), host-guest (Rebek), glycan (CH-pi/boronic)
  - glycan/ring_enumerator.py: re-export wrapper (backward compat)
  - 30 tests + zero regression on 376 existing tests

Requires: all previous bootstraps applied + RDKit
Usage: python bootstrap_core_demand.py
"""
import base64, os, sys

if os.path.isfile("core/universal_schema.py"): root="."
elif os.path.isfile(os.path.join("..","core","universal_schema.py")): root=".."; os.chdir(root)
else: print("ERROR: Run from MABE root"); sys.exit(1)

FILES = {
    'core/ring_enumerator.py': '',
    'core/demand_generator.py': '',
    'glycan/ring_enumerator.py': '',
    'tests/test_demand_generator.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")

print()
print("Done. Run:")
print("  python -m pytest tests/test_demand_generator.py -v")